export function TechPage({ navigate }) {
  useScrollReveal();
  return (
    <div className="tech page-enter">

      {/* ── Hero ── */}
      <section className="tech-hero">
        <div className="tech-hero__bg"/>
        <div className="tech-hero__ov"/>
        <div className="tech-hero__grid tech-grid-bg"/>
        <div className="tech-hero__bleed">TECH</div>
        <div className="tech-hero__content">
          <div className="eyebrow" data-reveal="up">Under the Hood</div>
          <h1 className="tech-hero__h1" data-reveal="up">
            Built on proven<br /><em className="gold-text">cryptography.</em>
          </h1>
          <p className="tech-hero__sub" data-reveal="up">
            Every component relies on well-established cryptographic primitives —
            nothing proprietary, nothing trusted, nothing that can be taken away.
          </p>
        </div>
      </section>

      {/* ── Contract code ── */}
      <section className="tech-contract">
        <div className="tech-contract__bleed">CODE</div>
        <div className="tech-contract__inner">
          <div className="tech-contract__left -l" data-reveal="up">
            <div className="eyebrow">The Smart Contract</div>
            <h2 className="section-h tech-contract__h2">
              PaperRegistry.sol —<br />the entire system<br />
              <em className="gold-text">in 50 lines.</em>
            </h2>
            <p className="tech-contract__desc">
              No owner. No admin. No backdoor. Once deployed, this contract runs
              exactly as written, forever. The code is the only authority.
            </p>
            <div className="tech-contract__stats">
              {[
                {v:"50",  l:"Lines of Solidity"},
                {v:"16",  l:"Tests passing"},
                {v:"0",   l:"Admin privileges"},
                {v:"∞",   l:"Permanence"},
              ].map(({v,l})=>(
                <div className="tech-contract__stat" key={l}>
                  <div className="tech-contract__stat-v">{v}</div>
                  <div className="tech-contract__stat-l">{l}</div>
                </div>
              ))}
            </div>
          </div>
          <div className="tech-contract__right r-" data-reveal="up">
            <div className="tech-contract__code-wrap">
              <div className="tech-contract__code-bar">
                <span style={{background:"#e05252"}}/>
                <span style={{background:"#f0a500"}}/>
                <span style={{background:"#4ecba0"}}/>
                <span className="tech-contract__code-name">PaperRegistry.sol</span>
              </div>
              <pre className="tech-contract__code">{CONTRACT_CODE}</pre>
            </div>
          </div>
        </div>
      </section>

      {/* ── Tech cards ── */}
      <section className="tech-cards">
        <div className="tech-cards__inner">
          <div className="eyebrow" data-reveal="up">The Stack</div>
          <h2 className="section-h tech-cards__h2" data-reveal="up">Every component explained.</h2>
          <div className="tech-cards__grid">
            {techCards.map((c,i) => (
              <div className="tech-card" data-reveal="up" key={c.title} style={{"--a":c.accent,"--delay":`${i*0.1}s`}}>
                <div className="tech-card__img-wrap">
                  <img src={c.img} alt={c.title} className="tech-card__img" loading="lazy"/>
                  <div className="tech-card__img-ov"/>
                  <div className="tech-card__icon">{c.icon}</div>
                </div>
                <div className="tech-card__body">
                  <div className="tech-card__sub">{c.sub}</div>
                  <h3 className="tech-card__title">{c.title}</h3>
                  <p className="tech-card__desc">{c.desc}</p>
                  <ul className="tech-card__details">
                    {c.details.map(d=>(
                      <li key={d} className="tech-card__detail">
                        <span className="tech-card__bullet"/>
                        {d}
                      </li>
                    ))}
                  </ul>
                  <div className="tech-card__tags">
                    {c.tags.map(t=><span className="tech-card__tag" key={t}>{t}</span>)}
                  </div>
                </div>
              </div>
            ))}
          </div>
        </div>
      </section>

      {/* ── Architecture diagram ── */}
      <section className="tech-arch">
        <div className="tech-arch__bleed">ARCH</div>
        <div className="tech-arch__inner">
          <div className="eyebrow" data-reveal="up">Architecture</div>
          <h2 className="section-h tech-arch__h2" data-reveal="up">How all the parts connect.</h2>
          <div className="tech-arch__diagram" data-reveal="up">
            {[
              {layer:"Frontend", items:["React App","ethers.js v6","Pinata SDK"], color:"#b8922a"},
              {layer:"Blockchain", items:["Hardhat Node / Polygon","PaperRegistry.sol","EVM Execution"], color:"#3d7fff"},
              {layer:"Storage", items:["IPFS Protocol","Pinata Pinning","CID v1 SHA-256"], color:"#1a6b5a"},
            ].map(({layer,items,color}) => (
              <div className="tech-arch__layer" key={layer} style={{"--c":color}}>
                <div className="tech-arch__layer-label">{layer}</div>
                <div className="tech-arch__layer-items">
                  {items.map(item=>(
                    <div className="tech-arch__item" key={item}>{item}</div>
                  ))}
                </div>
              </div>
            ))}
          </div>
        </div>
      </section>

      {/* ── CTA ── */}
      <section className="tech-cta">
        <div className="tech-cta__inner" data-reveal="up">
          <h2 className="section-h tech-cta__h2">
            Now that you know how it's built —
          </h2>
          <div className="tech-cta__btns">
            <button className="btn btn-gold" onClick={() => { navigate("app"); window.scrollTo(0,0); }}>
              <span>Launch the App →</span>
            </button>
            <button className="btn btn-ghost" onClick={() => { navigate("how"); window.scrollTo(0,0); }}>
              Review How It Works
            </button>
          </div>
        </div>
      </section>
    </div>
  );
}
